class WebViewScreen extends StatefulWidget {
  @override
  _WebViewScreenState createState() => _WebViewScreenState();
}

class _WebViewScreenState extends State<WebViewScreen> {
  late WebViewController _controller;
  final ImagePicker _imagePicker = ImagePicker();
  FirebaseMessaging? _firebaseMessaging;
  bool isLoading = true;

  @override
  void initState() {
    super.initState();
    _initializeFirebaseMessaging();
  }

  void _initializeFirebaseMessaging() async {
    try {
      _firebaseMessaging = FirebaseMessaging.instance;
      
      NotificationSettings settings = await _firebaseMessaging!.requestPermission(
        alert: true,
        badge: true,
        sound: true,
      );

      if (settings.authorizationStatus == AuthorizationStatus.authorized) {
        String? token = await _firebaseMessaging!.getToken();
        print('FCM Token: $token');
        
        FirebaseMessaging.onMessage.listen((RemoteMessage message) {
          _handleNotification(message);
        });

        FirebaseMessaging.onMessageOpenedApp.listen((RemoteMessage message) {
          _handleNotification(message);
        });
      }
    } catch (e) {
      print('Firebase initialization error: $e');
    }
  }

  void _handleNotification(RemoteMessage message) {
    Map<String, dynamic> notificationData = {
      'title': message.notification?.title ?? '',
      'body': message.notification?.body ?? '',
      'data': message.data,
    };
    
    _sendMessageToWeb('onNotificationReceived', notificationData);
  }

  void _sendMessageToWeb(String event, Map<String, dynamic> data) {
    final message = jsonEncode({'event': event, 'data': data});
    _controller.runJavaScript(
      'window.dispatchEvent(new CustomEvent("flutterMessage", {detail: $message}))'
    );
  }

  Future<void> _openCamera() async {
    try {
      final XFile? image = await _imagePicker.pickImage(
        source: ImageSource.camera,
        maxWidth: 1920,
        maxHeight: 1080,
        imageQuality: 85,
      );

      if (image != null) {
        final bytes = await image.readAsBytes();
        final base64Image = base64Encode(bytes);
        
        _sendMessageToWeb('onCameraResult', {
          'success': true,
          'image': 'data:image/jpeg;base64,$base64Image',
          'path': image.path,
        });
      } else {
        _sendMessageToWeb('onCameraResult', {
          'success': false,
          'error': 'User cancelled camera',
        });
      }
    } catch (e) {
      _sendMessageToWeb('onCameraResult', {
        'success': false,
        'error': e.toString(),
      });
    }
  }

  Future<void> _openGallery() async {
    try {
      final XFile? image = await _imagePicker.pickImage(
        source: ImageSource.gallery,
        maxWidth: 1920,
        maxHeight: 1080,
        imageQuality: 85,
      );

      if (image != null) {
        final bytes = await image.readAsBytes();
        final base64Image = base64Encode(bytes);
        
        _sendMessageToWeb('onGalleryResult', {
          'success': true,
          'image': 'data:image/jpeg;base64,$base64Image',
          'path': image.path,
        });
      } else {
        _sendMessageToWeb('onGalleryResult', {
          'success': false,
          'error': 'User cancelled gallery selection',
        });
      }
    } catch (e) {
      _sendMessageToWeb('onGalleryResult', {
        'success': false,
        'error': e.toString(),
      });
    }
  }

  Future<void> _requestNotificationPermission() async {
    try {
      if (_firebaseMessaging != null) {
        NotificationSettings settings = await _firebaseMessaging!.requestPermission(
          alert: true,
          badge: true,
          sound: true,
        );

        String? token = await _firebaseMessaging!.getToken();
        
        _sendMessageToWeb('onNotificationPermission', {
          'granted': settings.authorizationStatus == AuthorizationStatus.authorized,
          'token': token ?? '',
        });
      }
    } catch (e) {
      _sendMessageToWeb('onNotificationPermission', {
        'granted': false,
        'error': e.toString(),
      });
    }
  }

  void _handleJavaScriptMessage(JavaScriptMessage message) {
    try {
      final data = jsonDecode(message.message);
      final action = data['action'];

      switch (action) {
        case 'openCamera':
          _openCamera();
          break;
        case 'openGallery':
          _openGallery();
          break;
        case 'requestNotificationPermission':
          _requestNotificationPermission();
          break;
        case 'getDeviceInfo':
          _sendMessageToWeb('onDeviceInfo', {
            'platform': Theme.of(context).platform.toString(),
            'isAndroid': Theme.of(context).platform == TargetPlatform.android,
            'isIOS': Theme.of(context).platform == TargetPlatform.iOS,
          });
          break;
        default:
          print('Unknown action: $action');
      }
    } catch (e) {
      print('Error handling JavaScript message: $e');
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text('Hybrid WebView App'),
        actions: [
          IconButton(
            icon: Icon(Icons.refresh),
            onPressed: () {
              _controller.reload();
            },
          ),
        ],
      ),
      body: Stack(
        children: [
          WebView(
            initialUrl: 'https://your-mobile-website.com',
            javascriptMode: JavascriptMode.unrestricted,
            onWebViewCreated: (WebViewController controller) {
              _controller = controller;
            },
            javascriptChannels: {
              JavascriptChannel(
                name: 'FlutterChannel',
                onMessageReceived: _handleJavaScriptMessage,
              ),
            },
            onPageStarted: (String url) {
              setState(() {
                isLoading = true;
              });
            },
            onPageFinished: (String url) {
              setState(() {
                isLoading = false;
              });
              
              _controller.runJavaScript('''
                window.FlutterBridge = {
                  openCamera: function() {
                    FlutterChannel.postMessage(JSON.stringify({action: 'openCamera'}));
                  },
                  openGallery: function() {
                    FlutterChannel.postMessage(JSON.stringify({action: 'openGallery'}));
                  },
                  requestNotificationPermission: function() {
                    FlutterChannel.postMessage(JSON.stringify({action: 'requestNotificationPermission'}));
                  },
                  getDeviceInfo: function() {
                    FlutterChannel.postMessage(JSON.stringify({action: 'getDeviceInfo'}));
                  }
                };
              ''');
            },
            gestureNavigationEnabled: true,
            allowsInlineMediaPlayback: true,
          ),
          if (isLoading)
            Center(
              child: CircularProgressIndicator(),
            ),
        ],
      ),
    );
  }
}